const body = $json.body || {};
const client = {
  name: body.contact_name || body.first_name || 'Cliente',
  email: body.email || body.contact_email || '',
  phone: body.phone || body.contact_phone || '',
  date: body.appointment_start_time || body.date || '',
  duration: body.duration || body.appointment_duration || '30 min',
  notes: body.notes || body.issue || body.message || 'Sem notas',
  type: body.appointment_type || 'Suporte',
  calendar: body.calendar_name || 'Help Center'
};

const now = new Date();
return [{ json: {
  ...client,
  receivedAt: now.toISOString(),
  aiPrompt: 'Resumo rapido da situacao do cliente para a equipe antes da chamada:\n\nCliente: ' + client.name + '\nTipo: ' + client.type + '\nNotas/Problema: ' + client.notes + '\n\nEm 2-3 frases em portugues, faca um briefing claro: o que o cliente precisa e o que a equipe deve preparar antes da chamada.'
}}];
